const daysPastDue = Math.floor((Date.now() - new Date(items[0].json.due_date)) / 86400000);
let tone = 'friendly';
let subject = 'Friendly reminder: Invoice #' + items[0].json.invoice_number;
if (daysPastDue > 14) { tone = 'firm'; subject = 'Action required: Overdue invoice #' + items[0].json.invoice_number; }
if (daysPastDue > 30) { tone = 'urgent'; subject = 'URGENT: Invoice #' + items[0].json.invoice_number + ' is significantly overdue'; }
return [{ json: { ...items[0].json, daysPastDue, tone, subject } }];
